INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1000001, "2030/01/01 14:59:59", 62, 2, 3.414, "カリン", 190805, 1, 1, "2025/01/31 12:00:00", -416.5, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1000002, "2030/01/01 14:59:59", 62, 2, 3.099, "カリン", 190805, 2, 1, "2025/01/31 12:00:00", -416.5, "ミッションをクリアして、\n報酬をゲットしましょう！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1000003, "2030/01/01 14:59:59", 63, 2, 2.801, "カリン", 190805, 3, 1, "2025/01/31 12:00:00", -416.5, "受け取ることができる\n報酬があるようです\n確認してみてください");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 1000004, "2030/01/01 14:59:59", 63, 2, 0.0, "カリン", 190805, 4, 1, "2025/01/31 12:00:00", -416.5, "報酬がもらえますよ！\nチェックしてみてください");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 1000005, "2030/01/01 14:59:59", 64, 1, 2.12, "カリン", 190805, 5, 1, "2025/01/31 12:00:00", -363.0, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1000006, "2030/01/01 14:59:59", 64, 2, 1.68, "カリン", 190805, 6, 1, "2025/01/31 12:00:00", -363.0, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 1000007, "2030/01/01 14:59:59", 64, 1, 2.33, "カリン", 190805, 7, 1, "2025/01/31 12:00:00", -363.0, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, -6.0, 1020101, "2030/01/01 14:59:59", 61, 7, 5.18, "ラビリスタ", 133701, 101, 10201, "2025/01/31 12:00:00", -285.0, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, -2.0, 1020102, "2030/01/01 14:59:59", 61, 2, 8.77, "クリスティーナ", 133901, 201, 10201, "2025/01/31 12:00:00", -285.0, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (6, 0.0, 1020103, "2030/01/01 14:59:59", 61, 1, 15.5, "ネネカ", 133801, 301, 10201, "2025/01/31 12:00:00", -285.0, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 1020201, "2030/01/01 14:59:59", 61, 5, 9.061, "ランファ", 134301, 101, 10202, "2025/02/28 12:00:00", -285.0, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1020202, "2030/01/01 14:59:59", 61, 2, 7.699, "チカ", 134401, 201, 10202, "2025/02/28 12:00:00", -285.0, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1020301, "2030/01/01 14:59:59", 61, 2, 8.595, "アオイ", 134601, 101, 10203, "2025/03/31 12:00:00", -285.0, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1020302, "2030/01/01 14:59:59", 61, 2, 7.758, "クローチェ", 134501, 201, 10203, "2025/03/31 12:00:00", -285.0, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 1020401, "2030/01/01 14:59:59", 61, 6, 7.0, "ルイズマリー", 132302, 101, 10204, "2025/04/30 12:00:00", -285.0, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1020402, "2030/01/01 14:59:59", 61, 2, 7.904, "イロハ", 132402, 201, 10204, "2025/04/30 12:00:00", -285.0, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, 0.0, 1020403, "2030/01/01 14:59:59", 61, 2, 8.487, "ソノ", 132502, 301, 10204, "2025/04/30 12:00:00", -285.0, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1020502, "2030/01/01 14:59:59", 61, 2, 8.763, "カノン", 134901, 101, 10205, "2025/05/31 12:00:00", -285.0, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1020503, "2030/01/01 14:59:59", 61, 3, 6.417, "ツムギ", 134801, 201, 10205, "2025/05/31 12:00:00", -285.0, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, 0.0, 1020601, "2030/01/01 14:59:59", 61, 7, 10.335, "エリス", 135001, 101, 10206, "2025/06/30 12:00:00", -285.0, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 1020602, "2030/01/01 14:59:59", 61, 4, 6.281, "シェフィ", 135101, 201, 10206, "2025/06/30 12:00:00", -285.0, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1020603, "2030/01/01 14:59:59", 61, 2, 12.244, "プレシア", 135201, 301, 10206, "2025/06/30 12:00:00", -285.0, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 1020701, "2030/01/01 14:59:59", 61, 8, 6.339, "クリア", 135301, 101, 10207, "2025/07/31 12:00:00", -285.0, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (7, 0.0, 1020702, "2030/01/01 14:59:59", 61, 9, 8.184, "アネモネ", 135401, 201, 10207, "2025/07/31 12:00:00", -285.0, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (9, 0.0, 1020801, "2030/01/01 14:59:59", 61, 2, 3.906, "アイラ", 129101, 101, 10208, "2025/08/31 12:00:00", -285.0, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1020802, "2030/01/01 14:59:59", 61, 2, 14.465, "シナツ", 129201, 201, 10208, "2025/08/31 12:00:00", -285.0, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, 0.0, 1020803, "2030/01/01 14:59:59", 61, 3, 8.662, "ヒヨリ", 100101, 301, 10208, "2025/08/31 12:00:00", -285.0, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1020804, "2030/01/01 14:59:59", 61, 3, 10.915, "レイ", 100301, 401, 10208, "2025/08/31 12:00:00", -285.0, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1020901, "2030/01/01 14:59:59", 61, 7, 6.042, "ユキノ", 135802, 101, 10209, "2025/09/30 12:00:00", -285.0, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, 0.0, 1020902, "2030/01/01 14:59:59", 61, 1, 9.402, "サツキ", 135903, 201, 10209, "2025/09/30 12:00:00", -285.0, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (8, 0.0, 1020903, "2030/01/01 14:59:59", 61, 1, 8.16, "ルルィ", 136902, 301, 10209, "2025/09/30 12:00:00", -285.0, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, 0.0, 1021001, "2030/01/01 14:59:59", 61, 2, 5.0, "カスミ", 137401, 101, 10210, "2025/10/31 12:00:00", -285.0, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, 0.0, 1021002, "2030/01/01 14:59:59", 61, 1, 8.12, "アラクネ", 136001, 201, 10210, "2025/10/31 12:00:00", -285.0, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, 0.0, 1021003, "2030/01/01 14:59:59", 61, 2, 6.386, "ナーナ", 136202, 301, 10210, "2025/10/31 12:00:00", -285.0, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, 0.0, 1021101, "2030/01/01 14:59:59", 61, 4, 7.438, "ユイ", 136402, 101, 10211, "2025/11/30 12:00:00", -285.0, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1021102, "2030/01/01 14:59:59", 61, 5, 8.35, "ミソラ", 136302, 201, 10211, "2025/11/30 12:00:00", -285.0, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1021201, "2030/01/01 14:59:59", 61, 2, 5.0, "シズル", 136501, 101, 10212, "2025/12/31 12:00:00", -285.0, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1021202, "2030/01/01 14:59:59", 61, 2, 5.25, "リノ", 137902, 201, 10212, "2025/12/31 12:00:00", -285.0, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1021203, "2030/01/01 14:59:59", 61, 2, 7.5, "ラビリスタ", 106801, 301, 10212, "2025/12/31 12:00:00", -285.0, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1021301, "2030/01/01 14:59:59", 61, 2, 8.204, "ライラエル", 126501, 101, 10213, "2026/01/31 12:00:00", -285.0, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1021302, "2030/01/01 14:59:59", 61, 2, 7.176, "ネフィ＝ネラ", 129701, 201, 10213, "2026/01/31 12:00:00", -285.0, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1021303, "2030/01/01 14:59:59", 61, 5, 8.602, "ヴァイオレット", 133101, 301, 10213, "2026/01/31 12:00:00", -285.0, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1021304, "2030/01/01 14:59:59", 61, 3, 10.14, "ライラエル", 138101, 102, 10213, "2026/02/06 12:00:00", -285.0, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1021305, "2030/01/01 14:59:59", 61, 7, 10.152, "ネフィ＝ネラ", 138201, 202, 10213, "2026/02/06 12:00:00", -285.0, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, 0.0, 1021306, "2030/01/01 14:59:59", 61, 3, 9.688, "ヴァイオレット", 138001, 302, 10213, "2026/02/06 12:00:00", -285.0, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 1021307, "2030/01/01 14:59:59", 61, 1, 5.928, "ペコリーヌ", 138301, 401, 10213, "2026/02/12 12:00:00", -285.0, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, 0.0, 1021401, "2030/01/01 14:59:59", 61, 2, 9.19, "ワカナ", 138702, 101, 10214, "2026/02/28 12:00:00", -285.0, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1021402, "2030/01/01 14:59:59", 61, 3, 8.724, "シオリ", 138802, 201, 10214, "2026/02/28 12:00:00", -285.0, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, 0.0, 1021501, "2030/01/01 14:59:59", 61, 1, 7.758, "グレイス", 138902, 101, 10215, "2026/03/31 12:00:00", -285.0, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (6, 0.0, 1021502, "2030/01/01 14:59:59", 61, 4, 6.375, "キョウカ", 139002, 201, 10215, "2026/03/31 12:00:00", -285.0, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (6, 0.0, 1021503, "2030/01/01 14:59:59", 61, 1, 6.173, "ルルィ", 136902, 301, 10215, "2026/03/31 12:00:00", -285.0, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (6, 0.0, 1021601, "2030/01/01 14:59:59", 61, 2, 4.202, "ミホ", 139202, 101, 10216, "2026/04/30 12:00:00", -285.0, "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (6, 0.0, 1021602, "2030/01/01 14:59:59", 61, 1, 2.842, "マホ", 139302, 201, 10216, "2026/04/30 12:00:00", -285.0, "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, 0.0, 1021603, "2030/01/01 14:59:59", 61, 1, 4.598, "エリカ", 139402, 301, 10216, "2026/04/30 12:00:00", -285.0, "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (4, 0.0, 1021701, "2030/01/01 14:59:59", 61, 3, 6.533, "リリ", 125802, 101, 10217, "2026/05/31 12:00:00", -285.0, "わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, 0.0, 1021702, "2030/01/01 14:59:59", 61, 3, 5.0, "プレシア", 126102, 301, 10217, "2026/05/31 12:00:00", -285.0, "みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, 0.0, 1021703, "2030/01/01 14:59:59", 61, 4, 5.214, "クリア", 126002, 201, 10217, "2026/05/31 12:00:00", -285.0, "癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 1021704, "2030/01/01 14:59:59", 61, 3, 8.781, "リリ", 139501, 102, 10217, "2026/05/31 12:00:00", -285.0, "ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 1021705, "2030/01/01 14:59:59", 61, 1, 6.529, "クリア", 139601, 202, 10217, "2026/05/31 12:00:00", -285.0, "このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (3, 0.0, 1021706, "2030/01/01 14:59:59", 61, 2, 3.195, "プレシア", 139701, 302, 10217, "2026/05/31 12:00:00", -285.0, "ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 1021801, "2030/01/01 14:59:59", 61, 3, 12.43, "ルイズマリー", 139902, 101, 10218, "2026/06/30 12:00:00", -285.0, "ダーリンと一緒に南の島で\nリゾート開発なんて夢みたい♪\nああ…幸せ、最高の夏だわ…\n触れたら爆発さえしなければ～…っ");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 1021802, "2030/01/01 14:59:59", 61, 3, 6.35, "クレジッタ", 140001, 201, 10218, "2026/06/30 12:00:00", -285.0, "青い空、白い雲…無人島リゾートで\n大儲けですわ～♪　こらこらそこ、\nイチャついてるんじゃないですのよ\n触れたらドカンですわよ、ドカン！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 2000001, "2030/01/01 14:59:59", 62, 2, 3.414, "カリン", 190801, 1, 2, "2026/04/10 12:00:00", -416.5, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 2000002, "2030/01/01 14:59:59", 62, 2, 3.099, "カリン", 190801, 2, 2, "2026/04/10 12:00:00", -416.5, "ミッションをクリアして、\n報酬をゲットしましょう！");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 2000003, "2030/01/01 14:59:59", 63, 2, 2.801, "カリン", 190801, 3, 2, "2026/04/10 12:00:00", -416.5, "受け取ることができる\n報酬があるようです\n確認してみてください");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 2000004, "2030/01/01 14:59:59", 63, 2, 0.0, "カリン", 190801, 4, 2, "2026/04/10 12:00:00", -416.5, "報酬がもらえますよ！\nチェックしてみてください");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 2000005, "2030/01/01 14:59:59", 64, 1, 2.12, "カリン", 190801, 5, 2, "2026/04/10 12:00:00", -363.0, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1, 0.0, 2000006, "2030/01/01 14:59:59", 64, 2, 1.68, "カリン", 190801, 6, 2, "2026/04/10 12:00:00", -363.0, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ");
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2, 0.0, 2000007, "2030/01/01 14:59:59", 64, 1, 2.33, "カリン", 190801, 7, 2, "2026/04/10 12:00:00", -363.0, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね");
